use std::io;

macro_rules! readln {
    () => {{
        use std::io;
        let mut buf = String::new();
        io::stdin().read_line(&mut buf).unwrap();
        buf.trim().to_string()
    }};
    ( $t:ty ) => {{
        let input = readln!();
        input.parse::<$t>().unwrap()
    }};
    ( $( $t:ty ),+ ) => {{
        let input = readln!();
        let mut input = input.split_whitespace();
        (
            $(
                input.next().unwrap().parse::<$t>().unwrap(),
            )+
        )
    }}
}

fn div_and_ceil(n1: i32, n2: i32) -> i32 {
    if n1 % n2 == 0 {
        n1 / n2
    } else {
        n1 / n2 + 1
    }
}

fn main() {
    let count = readln!(i32);
    let width = (count as f64).sqrt() as i32;
    println!("{}", width + div_and_ceil(count, width));
}
